package com.enterprise.jsf;

import javax.servlet.*;
import javax.servlet.http.*;
import javax.crypto.Cipher;
import javax.crypto.Mac;
import javax.crypto.spec.IvParameterSpec;
import javax.crypto.spec.SecretKeySpec;
import java.util.Arrays;
import java.util.Base64;

/** Verifies + decrypts the JSF ViewState inline on each postback (encrypt-then-MAC). */
public class ViewStateFilter implements Filter {

    private final byte[] encKey;   // SHA-256(pass)[:16]
    private final byte[] macKey;   // SHA-256("MAC:" + pass)

    public ViewStateFilter(byte[] encKey, byte[] macKey) {
        this.encKey = encKey;
        this.macKey = macKey;
    }

    @Override
    public void doFilter(ServletRequest req, ServletResponse resp, FilterChain chain)
            throws java.io.IOException, ServletException {
        String token = req.getParameter("javax.faces.ViewState");
        if (token != null) {
            try {
                byte[] all = Base64.getDecoder().decode(token);
                Mac mac = Mac.getInstance("HmacSHA1");
                mac.init(new SecretKeySpec(macKey, "HmacSHA1"));
                int macLen = mac.getMacLength();
                byte[] iv = Arrays.copyOfRange(all, 0, 16);
                byte[] ct = Arrays.copyOfRange(all, 16, all.length - macLen);
                mac.update(iv); mac.update(ct);
                byte[] calc = mac.doFinal();
                boolean ok = true;
                for (int i = 0; i < calc.length; i++)
                    if (calc[i] != all[all.length - macLen + i]) { ok = false; break; }
                if (ok) {
                    Cipher c = Cipher.getInstance("AES/CBC/PKCS5Padding");
                    c.init(Cipher.DECRYPT_MODE, new SecretKeySpec(encKey, "AES"), new IvParameterSpec(iv));
                    req.setAttribute("viewState", c.doFinal(ct));
                }
            } catch (Exception ignored) { /* invalid view state -> treated as absent */ }
        }
        chain.doFilter(req, resp);
    }
    @Override public void init(FilterConfig f) {}
    @Override public void destroy() {}
}
