package com.acme.cms.view;

import org.apache.myfaces.shared.util.StateUtils;
import javax.faces.context.ExternalContext;

/** Centralizes authenticated ViewState handling on MyFaces 1.2.9 (shared-impl 3.0.8). */
public class ViewStateProtector {

    private final ExternalContext ctx;   // carries the AES secret, the MAC secret, and HmacSHA1 config

    public ViewStateProtector(ExternalContext ctx) {
        this.ctx = ctx;
    }

    /** encrypt-then-MAC: StateUtils encrypts, then appends the HmacSHA1 tag over IV || ciphertext. */
    public byte[] mint(byte[] viewState) {
        return StateUtils.encrypt(viewState, ctx);
    }

    /** verify-then-decrypt: StateUtils checks the MAC before decrypting; throws on mismatch. */
    public byte[] check(byte[] token) {
        return StateUtils.decrypt(token, ctx);
    }
}
