/** Stateless authenticated ViewState codec (encrypt-then-MAC). No instances. */
public final class AuthenticatedCodec {

    private AuthenticatedCodec() { }

    public static byte[] seal(byte[] viewState, ExternalContext ctx) {
        return StateUtils.encrypt(viewState, ctx);   // AES-CBC then HmacSHA1 over IV || ciphertext
    }

    public static byte[] open(byte[] token, ExternalContext ctx) {
        return StateUtils.decrypt(token, ctx);       // MAC verified first; decrypt only on match
    }
}
