package com.bank.portal.view;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;
import java.security.MessageDigest;
import java.util.Arrays;

/** Spring component holding the dual-derived ViewState keys (MyFaces encrypt-then-MAC). */
@Component
public class ViewStateCipher {

    private final byte[] encKey;
    private final byte[] macKey;

    public ViewStateCipher(@Value("${viewstate.passphrase}") String passphrase) throws Exception {
        byte[] sha = MessageDigest.getInstance("SHA-256").digest(passphrase.getBytes("UTF-8"));
        this.encKey = Arrays.copyOf(sha, 16);                                   // AES-128 key
        this.macKey = MessageDigest.getInstance("SHA-256")
                .digest(("MAC:" + passphrase).getBytes("UTF-8"));               // separate HmacSHA1 key
    }

    public byte[] encryptionKey() { return encKey; }
    public byte[] macAuthKey()    { return macKey; }
}
