// Encryption key = first 16 bytes of SHA-256(key); separate MAC key = SHA-256("MAC:" + key).
import javax.crypto.Cipher;
import javax.crypto.Mac;
import javax.crypto.spec.IvParameterSpec;
import javax.crypto.spec.SecretKeySpec;
import java.security.MessageDigest;
import java.util.Arrays;
import java.util.Base64;

class AuthOracle {
    static byte[] encKey(String key) throws Exception {
        return Arrays.copyOf(MessageDigest.getInstance("SHA-256").digest(key.getBytes("UTF-8")), 16);
    }
    static byte[] macKey(String key) throws Exception {
        return MessageDigest.getInstance("SHA-256").digest(("MAC:" + key).getBytes("UTF-8"));
    }
    // Authenticated decrypt: verify the encrypt-then-MAC HmacSHA1 tag, then (only on success) decrypt.
    static String open(String state, byte[] ekey, byte[] mkey) {
        try {
            byte[] data = Base64.getDecoder().decode(state);
            Mac mac = Mac.getInstance("HmacSHA1");
            mac.init(new SecretKeySpec(mkey, "HmacSHA1"));
            int macLen = mac.getMacLength();
            int ctLen = data.length - 16 - macLen;
            if (ctLen < 16 || ctLen % 16 != 0) return "";
            byte[] iv = Arrays.copyOfRange(data, 0, 16);
            byte[] ct = Arrays.copyOfRange(data, 16, 16 + ctLen);
            mac.update(iv);
            mac.update(ct);
            byte[] calc = mac.doFinal();                 // encrypt-then-MAC tag over IV || ct
            boolean isMacEqual = true;
            for (int i = 0; i < calc.length; i++)
                if (calc[i] != data[16 + ctLen + i]) { isMacEqual = false; break; }
            if (!isMacEqual) return "";                  // MAC mismatch -> reject BEFORE decrypt
            Cipher cipher = Cipher.getInstance("AES/CBC/PKCS5Padding");
            cipher.init(Cipher.DECRYPT_MODE, new SecretKeySpec(ekey, "AES"), new IvParameterSpec(iv));
            byte[] pt = cipher.doFinal(ct);              // only reached once the MAC verifies
            return Base64.getEncoder().encodeToString(pt);
        } catch (Exception e) {
            return "";                                   // uniform empty on ANY failure
        }
    }
}
