package svc.jsf.facade;

import org.apache.myfaces.shared.util.StateUtils;
import javax.faces.context.ExternalContext;

/** Bare static helpers for the facade's authenticated ViewState token. */
public class ViewStateCodec {

    public static byte[] encode(byte[] viewState, ExternalContext ctx) {
        return StateUtils.encrypt(viewState, ctx);   // encrypt-then-MAC (HmacSHA1 over IV || ciphertext)
    }

    public static byte[] decode(byte[] token, ExternalContext ctx) {
        return StateUtils.decrypt(token, ctx);       // MAC verified before decrypt; throws on mismatch
    }
}
